import{_ as l,o as i,c as t,O as e}from"./chunks/framework.1e3ff9a3.js";const u=JSON.parse('{"title":"能力编排","description":"","frontmatter":{},"headers":[],"relativePath":"product/orchestration.md","filePath":"product/orchestration.md","lastUpdated":1775815758000}'),o={name:"product/orchestration.md"};function r(n,a,h,d,s,c){return i(),t("div",null,a[0]||(a[0]=[e('<h1 id="能力编排" tabindex="-1">能力编排 <a class="header-anchor" href="#能力编排" aria-label="Permalink to &quot;能力编排&quot;">​</a></h1><p>能力编排用于把多个能力节点按顺序接成一条可执行工作链，适合那些不是一步完成、而是需要连续处理的任务。</p><h2 id="当前可用基础" tabindex="-1">当前可用基础 <a class="header-anchor" href="#当前可用基础" aria-label="Permalink to &quot;当前可用基础&quot;">​</a></h2><p>SmartFlow 现在已经具备这些基础能力：</p><ol><li>AI 识别需求</li><li>在权限范围内推荐 Skill</li><li>人工确认</li><li>执行单个能力</li><li>返回结果并保留审计</li></ol><p>这意味着平台已经可以稳定完成“识别需求 -&gt; 推荐能力 -&gt; 确认执行 -&gt; 返回结果”的单能力闭环。</p><h2 id="能力编排会带来什么" tabindex="-1">能力编排会带来什么 <a class="header-anchor" href="#能力编排会带来什么" aria-label="Permalink to &quot;能力编排会带来什么&quot;">​</a></h2><p>随着能力编排持续加入，平台会进一步支持：</p><ol><li>一个任务拆成多个步骤</li><li>多个 Skill 或多个能力节点按顺序执行</li><li>步骤之间传递参数、结果或文件引用</li><li>对高风险步骤追加确认</li><li>对整条任务链保留日志、审计和失败记录</li></ol><h2 id="适合哪些场景" tabindex="-1">适合哪些场景 <a class="header-anchor" href="#适合哪些场景" aria-label="Permalink to &quot;适合哪些场景&quot;">​</a></h2><p>当任务天然需要多步处理时，能力编排会更有价值，例如：</p><ol><li>先采集，再清洗，再生成报告</li><li>先读取数据，再转换，再写入目标系统</li><li>先生成结果文件，再通知或归档</li><li>把多个可复用能力组织成一条稳定任务链</li></ol><h2 id="当前阶段怎么理解" tabindex="-1">当前阶段怎么理解 <a class="header-anchor" href="#当前阶段怎么理解" aria-label="Permalink to &quot;当前阶段怎么理解&quot;">​</a></h2><p>如果你现在在评估这条方向，可以先这样理解：</p><ol><li>当前已经可以稳定完成单能力执行</li><li>多步骤能力编排会在现有执行基础上继续扩展</li><li>当任务涉及多次确认、参数传递、文件衔接或跨步骤追踪时，这条能力会更有价值</li></ol><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>SmartFlow 会在现有单能力执行基础上，继续扩展为可确认、可追踪、可审计的多步骤能力编排平台。</p>',17)]))}const m=l(o,[["render",r]]);export{u as __pageData,m as default};
